#include "envoy/extensions/filters/http/custom_header_injection/v3/custom_header_injection.pb.h"

#include "source/extensions/filters/http/custom_header_injection/filter.h"
#include "source/extensions/filters/http/well_known_names.h"

#include "test/mocks/http/mocks.h"
#include "test/mocks/stream_info/mocks.h"
#include "test/test_common/utility.h"

#include "gmock/gmock.h"
#include "gtest/gtest.h"

using testing::NiceMock;

namespace Envoy {
namespace Extensions {
namespace HttpFilters {
namespace CustomHeaderInjection {
namespace {

class CustomHeaderInjectionTest : public testing::Test {
public:
  const std::string simple_config_yaml = R"EOF(
headers:
  - header_name: x-custom
    header_value: custom-value
    inject_in_request: true
    inject_in_response: false
)EOF";

  const std::string request_response_config_yaml = R"EOF(
headers:
  - header_name: x-request-header
    header_value: request-value
    inject_in_request: true
    inject_in_response: false
  - header_name: x-response-header
    header_value: response-value
    inject_in_request: false
    inject_in_response: true
)EOF";

  void initializeFilter(const std::string& yaml) {
    envoy::extensions::filters::http::custom_header_injection::v3::Config config;
    TestUtility::loadFromYaml(yaml, config);
    config_ = std::make_shared<Config>(config);
    filter_ = std::make_shared<CustomHeaderInjectionFilter>(config_);
    filter_->setDecoderFilterCallbacks(decoder_callbacks_);
    filter_->setEncoderFilterCallbacks(encoder_callbacks_);
  }

  std::shared_ptr<Config> config_;
  std::shared_ptr<CustomHeaderInjectionFilter> filter_;
  NiceMock<Http::MockStreamDecoderFilterCallbacks> decoder_callbacks_;
  NiceMock<Http::MockStreamEncoderFilterCallbacks> encoder_callbacks_;
  NiceMock<Envoy::StreamInfo::MockStreamInfo> req_info_;
};

/**
 * Test injecting custom header in request.
 */
TEST_F(CustomHeaderInjectionTest, InjectInRequest) {
  initializeFilter(simple_config_yaml);
  Http::TestRequestHeaderMapImpl headers;

  EXPECT_CALL(decoder_callbacks_, streamInfo()).WillRepeatedly(testing::ReturnRef(req_info_));

  auto status = filter_->decodeHeaders(headers, false);
  EXPECT_EQ(status, Http::FilterHeadersStatus::Continue);

  // Verify the header was injected
  EXPECT_EQ(headers.get("x-custom"), "custom-value");
}

/**
 * Test not injecting custom header in response when inject_in_response is false.
 */
TEST_F(CustomHeaderInjectionTest, NotInjectInResponseWhenDisabled) {
  initializeFilter(simple_config_yaml);
  Http::TestResponseHeaderMapImpl headers;

  EXPECT_CALL(encoder_callbacks_, streamInfo()).WillRepeatedly(testing::ReturnRef(req_info_));

  auto status = filter_->encodeHeaders(headers, false);
  EXPECT_EQ(status, Http::FilterHeadersStatus::Continue);

  // Verify the header was NOT injected
  EXPECT_FALSE(headers.has("x-custom"));
}

/**
 * Test injecting multiple headers in both request and response.
 */
TEST_F(CustomHeaderInjectionTest, InjectMultipleHeaders) {
  initializeFilter(request_response_config_yaml);
  Http::TestRequestHeaderMapImpl request_headers;
  Http::TestResponseHeaderMapImpl response_headers;

  EXPECT_CALL(decoder_callbacks_, streamInfo()).WillRepeatedly(testing::ReturnRef(req_info_));
  EXPECT_CALL(encoder_callbacks_, streamInfo()).WillRepeatedly(testing::ReturnRef(req_info_));

  // Test request header injection
  auto request_status = filter_->decodeHeaders(request_headers, false);
  EXPECT_EQ(request_status, Http::FilterHeadersStatus::Continue);
  EXPECT_EQ(request_headers.get("x-request-header"), "request-value");
  EXPECT_FALSE(request_headers.has("x-response-header"));

  // Test response header injection
  auto response_status = filter_->encodeHeaders(response_headers, false);
  EXPECT_EQ(response_status, Http::FilterHeadersStatus::Continue);
  EXPECT_EQ(response_headers.get("x-response-header"), "response-value");
  EXPECT_FALSE(response_headers.has("x-request-header"));
}

/**
 * Test that the filter continues processing when config is nullptr.
 */
TEST_F(CustomHeaderInjectionTest, ContinuesWithNullConfig) {
  initializeFilter(simple_config_yaml);
  Http::TestRequestHeaderMapImpl headers;

  // Manually set config to nullptr to test the safe handling
  filter_->config_ = nullptr;

  auto status = filter_->decodeHeaders(headers, false);
  EXPECT_EQ(status, Http::FilterHeadersStatus::Continue);
}

/**
 * Test that the filter lifecycle methods work correctly.
 */
TEST_F(CustomHeaderInjectionTest, FilterLifecycle) {
  initializeFilter(simple_config_yaml);

  // Test that onDestroy is callable
  filter_->onDestroy();
}

} // namespace
} // namespace CustomHeaderInjection
} // namespace HttpFilters
} // namespace Extensions
} // namespace Envoy
